5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 1.1;
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	};
15	
16	function roundUpToWholeG(amount: number): number {
17	  // Round to cents first to avoid float-precision artifacts like 100*1.10 = 110.00000000000001
18	  return Math.ceil(Math.round(amount * 100) / 100);
19	}
20	
21	function premiumFor(item: Item): number {
22	  const basePremium = BASE_PREMIUMS[item.type];
23	  return roundUpToWholeG(basePremium * FIRST_INSURANCE_SURCHARGE);
24	}
25	
26	export function quote(
27	  _customer: { yearsWithMHPCO: number },
28	  items: Item[],
29	  _previousContracts?: number,
30	): number {
31	  const itemsTotal = items.reduce((sum, item) => sum + premiumFor(item), 0);
32	  return itemsTotal + PROCESSING_FEE;
33	}
34	
